// C0684 · REST CRUD JSON (GET/POST/PUT/DELETE)
import Hapi from "@hapi/hapi";
const server = Hapi.server({ port: 3000 });

const items = new Map(); let seq = 1;

server.route({ method:"GET", path:"/items", handler:()=>[...items.values()] });

server.route({
  method:"POST",
  path:"/items",
  options:{ payload:{ parse:true, allow:"application/json" } },
  handler:(req,h)=>{
    const it = { id: seq++, name: String(req.payload?.name||"") };
    items.set(it.id,it);
    return h.response(it).code(201);
  }
});

