// C0685 · Middleware logging + tiempo de respuesta
import Hapi from "@hapi/hapi";
const server = Hapi.server({ port: 3000 });

server.ext("onRequest", (req, h)=>{ req.app.t0 = Date.now(); return h.continue; });
server.ext("onPreResponse", (req, h)=>{
  const ms = Date.now() - (req.app.t0 || Date.now());
  req.log(["timing"], `${req.method.toUpperCase()} ${req.path} ${ms}ms`);
  return h.continue;
});

