// Normalizar errores: interceptar Boom
server.ext("onPreResponse", (req, h)=>{
  const r = req.response;
  if (r.isBoom) {
    return h.response({ error: "internal", message: r.message }).code(r.output.statusCode);
  }
  return h.continue;
});

